      /* <flatten type="Javascript"> */
function init$GridQuery$(g) {
  var a = g._queryFilterString.split(String.fromCharCode(253));
  g._alterTitle = [null, [['%c', a[0], true], ['%s', g._itemName, true], ['%d1', formatDateView(a[2]), true], ['%d2', formatDateView(a[3]), true]]];
  var x = a[1];
  g._hiddenFields = [
    {Fields: 'gia, tien_nhap', Value: (x == '10')},
    {Fields: 'gia_nt, tien_nt_n, ty_gia, ma_nt', Value: (x == '10' || x == '20')}
  ];
}
